func:
let line = String(msg.payload).trim();
if (!line) return null;

let parts = line.split(",");

if (parts.length < 2) return null;

msg.raw = line;
msg.time = parts[0];      // keep as text
msg.type = parts[1];

if (msg.type === "TLM" && parts.length >= 5) {
    msg.target = parts[2];
    msg.parameter = parts[3];
    msg.value = parts[4];
}
else if (msg.type === "ACK" && parts.length >= 4) {
    msg.target = parts[2];
    msg.value = parts[3];
}
else if (msg.type === "ERR" && parts.length >= 3) {
    msg.error = parts[2];

    if (parts.length >= 4) {
        msg.errorContext = parts[3];
        try {
            msg.errorContextDecoded = decodeURIComponent(parts[3]);
        } catch (err) {
            msg.errorContextDecoded = parts[3];
        }
    }
}

return msg;

let state = flow.get("satState") || {};

if (!state.tlm) {
    state.tlm = {};
}
if (!state.lastAck) {
    state.lastAck = null;
}
if (!state.lastErr) {
    state.lastErr = null;
}
if (!state.time) {
    state.time = null;
}

if (msg.time) {
    state.time = msg.time;
}

if (msg.type === "TLM") {
    if (!msg.target || !msg.parameter) {
        return null;
    }

    if (!state.tlm[msg.target]) {
        state.tlm[msg.target] = {};
    }

    state.tlm[msg.target][msg.parameter] = {
        value: msg.value,
        time: msg.time
    };
}
else if (msg.type === "ACK") {
    state.lastAck = {
        target: msg.target || null,
        value: msg.value || null,
        time: msg.time || null
    };
}
else if (msg.type === "ERR") {
    state.lastErr = {
        error: msg.error || null,
        context: msg.errorContext || null,
        contextDecoded: msg.errorContextDecoded || null,
        time: msg.time || null
    };
}

flow.set("satState", state);

msg.state = state;
return msg;

let s = msg.state || {};
let tlm = s.tlm || {};

function getValue(target, parameter, fallback = "") {
    if (tlm[target] && tlm[target][parameter]) {
        return tlm[target][parameter].value;
    }
    return fallback;
}

msg.payload = {
    time: s.time || "",
    rtcCurrentTime: getValue("RTC", "CURRENT_TIME"),
    rtcSync: getValue("RTC", "SYNC"),
    ledEnable: getValue("LED", "ENABLE"),
    ledState: getValue("LED", "STATE"),
    ledColor: getValue("LED", "COLOR"),
    ledTelemetry: getValue("LED", "TELEMETRY"),
    telemetryEnable: getValue("TELEMETRY", "ENABLE"),
    telemetryInterval: getValue("TELEMETRY", "INTERVAL_S"),
    batteryTelemetry: getValue("BATTERY", "TELEMETRY"),
    batteryAvailable: getValue("BATTERY", "AVAILABLE"),
    onBattery: getValue("BATTERY", "ON_BATTERY"),
    chargeCurrentA: getValue("BATTERY", "CHARGE_CURRENT_A"),
    chargeVoltageV: getValue("BATTERY", "CHARGE_VOLTAGE_V"),
    chargePercentP: getValue("BATTERY", "CHARGE_PERCENT_P"),
    lastAck: s.lastAck,
    lastErr: s.lastErr
};

return msg;

if (!msg.payload.lastAck) {
    msg.payload = "";
    return msg;
}
msg.payload = [msg.payload.lastAck.time, msg.payload.lastAck.target, msg.payload.lastAck.value]
    .filter(v => v !== null && v !== undefined && v !== "")
    .join(" | ");
return msg;

if (!msg.payload.lastErr) {
    msg.payload = "";
    return msg;
}
msg.payload = [
    msg.payload.lastErr.time,
    msg.payload.lastErr.error,
    msg.payload.lastErr.contextDecoded
]
    .filter(v => v !== null && v !== undefined && v !== "")
    .join(" | ");
return msg;

let interval = flow.get("tlmInterval");

if (!Number.isFinite(interval) || interval < 1) {
    return null;
}

msg.payload = "SET,TELEMETRY,INTERVAL_S," + interval + "\n";
return msg;

msg.payload = [
    {
        enable: msg.payload.ledEnable || "",
        state: msg.payload.ledState || "",
        color: msg.payload.ledColor || "",
        telemetry: msg.payload.ledTelemetry || ""
    }
];
return msg;

msg.payload = [
    {
        telemetryEnable: msg.payload.telemetryEnable || "",
        telemetryInterval: msg.payload.telemetryInterval || ""
    }
];
return msg;

let errors = flow.get("errorLog") || [];

if (msg.type !== "ERR") {
    return null;
}

let newError = {
    time: msg.time || "",
    error: msg.error || "",
    raw: msg.raw || ""
};

errors.unshift(newError);

// keep only most recent 50 in memory
if (errors.length > 50) {
    errors = errors.slice(0, 50);
}

flow.set("errorLog", errors);

// only send the new row to the table
msg.payload = [newError];
return msg;

let interval = Number(msg.payload);

if (!Number.isFinite(interval) || interval < 1) {
    return null;
}

flow.set("tlmInterval", interval);
return null;

const iso = new Date().toISOString().replace(/\.\d{3}Z$/, "Z");
msg.payload = "SET,RTC,CURRENT_TIME," + iso + "\n";
return msg;

let packetLog = flow.get("packetLog") || [];

packetLog.unshift({
    time: msg.time || "",
    packetType: msg.type || "",
    target: msg.target || "",
    parameter: msg.parameter || "",
    value: msg.value || msg.error || "",
    raw: msg.raw || ""
});

packetLog = packetLog.slice(0, 25);
flow.set("packetLog", packetLog);

return {
    payload: {
        rows: packetLog
    }
};
